Recent changes: Added neighbor-counting logic using a Map for tallying neighbor counts. Only survival rule implemented (alive cells with 2 or 3 neighbors survive). No birth rule yet.

Current implementation:
```typescript
export const nextGeneration = (aliveCells: number[][]): number[][] => {
  const aliveSet = new Set(aliveCells.map(([x, y]) => `${x},${y}`));
  const neighborCounts = new Map<string, number>();

  for (const [x, y] of aliveCells) {
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        const key = `${x + dx},${y + dy}`;
        neighborCounts.set(key, (neighborCounts.get(key) || 0) + 1);
      }
    }
  }

  const result: number[][] = [];
  for (const [key, count] of neighborCounts) {
    const [x, y] = key.split(",").map(Number);
    if (aliveSet.has(key) && (count === 2 || count === 3)) {
      result.push([x, y]);
    }
  }

  return result;
};
```

